scwin.f_excel = async function() {

    if (ds_cntrWrkRslts.getRowCount() <= 0){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return false
    }
    let rtn = await $c.win.confirm( "Excel로 다운로드 하시겠습니까?" ); 
    if ( rtn ) {
        let sheetTitle = "운송할인할증실적현황";	
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xls",    // + ".xls",
            sheetName: sheetTitle,
            useStyle: true
        };

        $c.data.downloadGridViewExcel(gr_cntrWrkRslts, options, infoArr);
    }

}
